const text = $input.item.json.message?.text || '';
const cmd = text.split(' ')[0].toLowerCase();
return [{ json: { ...$input.item.json, command: cmd } }];

const rows = $input.all();
const now = new Date();
const thisMonth = now.getMonth();
const thisYear = now.getFullYear();

let personalTotal = 0, businessTotal = 0;
const categoryTotals = {};

for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  if (d.getMonth() !== thisMonth || d.getFullYear() !== thisYear) continue;
  const amt = parseFloat(r.Amount) || 0;
  if (r.Type === 'Business') businessTotal += amt;
  else personalTotal += amt;
  categoryTotals[r.Category] = (categoryTotals[r.Category] || 0) + amt;
}

const monthName = now.toLocaleString('en-IN', { month: 'long', year: 'numeric' });
const sortedCats = Object.entries(categoryTotals).sort((a,b) => b[1]-a[1]).slice(0, 5);
const catLines = sortedCats.map(([cat, amt]) => `  ${cat}: ₹${amt.toFixed(0)}`).join('\n');

const msg = `📊 *${monthName} Summary*\n\n👤 Personal: ₹${personalTotal.toFixed(0)}\n💼 Business: ₹${businessTotal.toFixed(0)}\n💰 Total: ₹${(personalTotal+businessTotal).toFixed(0)}\n\n*Top Categories:*\n${catLines || '  No data yet'}`;

return [{ json: { message: msg } }];

const rows = $input.all();
const now = new Date();
const thisMonth = now.getMonth();
const thisYear = now.getFullYear();

const catTotals = {};
let total = 0;
for (const row of rows) {
  const r = row.json;
  if (!r.Date || !r.Amount) continue;
  const d = new Date(r.Date);
  if (d.getMonth() !== thisMonth || d.getFullYear() !== thisYear) continue;
  const amt = parseFloat(r.Amount) || 0;
  const key = `${r.Category} (${r.Type})`;
  catTotals[key] = (catTotals[key] || 0) + amt;
  total += amt;
}

const sorted = Object.entries(catTotals).sort((a,b) => b[1]-a[1]);
const lines = sorted.map(([cat, amt]) => `${cat}: ₹${amt.toFixed(0)}`).join('\n');
const monthName = now.toLocaleString('en-IN', { month: 'long', year: 'numeric' });

const msg = `📋 *${monthName} Full Report*\n\n${lines || 'No expenses this month'}\n\n*Grand Total: ₹${total.toFixed(0)}*`;
return [{ json: { message: msg } }];

const rows = $input.all();
const cmdText = $('Telegram Trigger').item.json.message?.text || '';
const term = cmdText.replace('/search', '').trim().toLowerCase();

if (!term) {
  return [{ json: { message: '🔍 Usage: /search keyword\nExample: /search starbucks' } }];
}

const matches = rows
  .map(r => r.json)
  .filter(r => r.Merchant && (
    r.Merchant.toLowerCase().includes(term) ||
    (r.Notes || '').toLowerCase().includes(term) ||
    (r.Category || '').toLowerCase().includes(term)
  ))
  .slice(-10)
  .reverse();

if (matches.length === 0) {
  return [{ json: { message: `🔍 No results for "${term}"` } }];
}

const lines = matches.map(r => `📅 ${r.Date} | ${r.Merchant} | ₹${r.Amount} | ${r.Category}`).join('\n');
return [{ json: { message: `🔍 *Results for "${term}":*\n\n${lines}` } }];
